mapper.select:
SELECT id, username, password, phone, company_id AS companyId, user_type AS userType, status, activator_id AS activatorId, last_login AS lastLogin, create_time AS createTime FROM app_user
company_id = #{companyId}
AND username LIKE concat('%', #{username}, '%')
AND phone LIKE concat('%', #{phone}, '%')
AND status = #{status}
AND create_time >= #{createTimeStart}
AND create_time <= #{createTimeEnd}
ORDER BY create_time DESC
